class Solution:
    def minimumTeachings(self, n, languages, friendships):
        langs = [set(l) for l in languages]
        bad = set()
        for u, v in friendships:
            if langs[u - 1].isdisjoint(langs[v - 1]):
                bad.add(u)
                bad.add(v)
        if not bad:
            return 0
        best = len(bad)
        for lang in range(1, n + 1):
            cnt = 0
            for user in bad:
                if lang not in langs[user - 1]:
                    cnt += 1
            best = min(best, cnt)
        return best

