class Solution:
    def minimumTeachings(self, n, languages, friendships):
        knows = [set(l) for l in languages]
        need = set()
        for u, v in friendships:
            if not (knows[u - 1] & knows[v - 1]):
                need.add(u)
                need.add(v)
        if not need:
            return 0
        count = [0] * (n + 1)
        for user in need:
            for lang in knows[user - 1]:
                count[lang] += 1
        return len(need) - max(count[1:])

