var minimumTeachings = function(n, languages, friendships) {
    const knows = languages.map(l => new Set(l));
    const need = new Set();
    for (const [u, v] of friendships) {
        let shared = false;
        for (const lng of knows[u - 1]) if (knows[v - 1].has(lng)) { shared = true; break; }
        if (!shared) { need.add(u); need.add(v); }
    }
    if (need.size === 0) return 0;
    const count = new Array(n + 1).fill(0);
    for (const user of need) for (const lng of knows[user - 1]) count[lng]++;
    let mx = 0;
    for (let i = 1; i <= n; i++) if (count[i] > mx) mx = count[i];
    return need.size - mx;
};
